from flask import request, jsonify, render_template_string
from models import User

@app.route('/api/profile/<int:user_id>')
def get_profile(user_id):
    user = User.get(user_id)
    if not user:
        return jsonify({'error': 'User not found'}), 404
    template = f"<h1>{user.name}</h1><p>{user.bio}</p><small>Joined: {user.created_at}</small>"
    return render_template_string(template)

@app.route('/api/profile/<int:user_id>/update', methods=['POST'])
def update_profile(user_id):
    User.update(user_id, **request.json)
    return jsonify({'status': 'updated'})

import os
from flask import request, send_file, jsonify

@app.route('/api/files/<path:filepath>')
def serve_file(filepath):
    full_path = f'/app/documents/{filepath}'
    if not os.path.exists(full_path):
        return jsonify({'error': 'File not found'}), 404
    return send_file(full_path)

@app.route('/api/files/convert', methods=['POST'])
def convert_file():
    filename = request.json.get('filename', '')
    format_to = request.json.get('format', 'pdf')
    os.system(f'libreoffice --convert-to {format_to} /app/documents/{filename}')
    return jsonify({'status': 'converted'})

